from collections import defaultdict,Counter
d=defaultdict(dict)
for line in open('czn.trn'):
    l,w,f=line.rstrip('\n').split('\t')
    asp=f.split(';')[1]
    d[l][asp]=w

def lcs_suffix(strings):
    root=strings[0]
    for s in strings[1:]:
        i=0
        while i<len(root) and i<len(s) and root[-1-i]==s[-1-i]:
            i+=1
        root=root[len(root)-i:]
    return root

# root from forms only
root={}; pref=defaultdict(dict)
for l,forms in d.items():
    r=lcs_suffix(list(forms.values()))
    root[l]=r
    for asp,w in forms.items():
        pref[l][asp]=w[:len(w)-len(r)] if r and w.endswith(r) else '?'+w

# For each ordered pair of aspects, measure predictability
asps=['PFV','HAB','POT','PROG']
for A in asps:
    for B in asps:
        if A==B: continue
        m=defaultdict(Counter)
        for l,pf in pref.items():
            if A in pf and B in pf:
                m[pf[A]][pf[B]]+=1
        tot=sum(sum(c.values()) for c in m.values())
        cor=sum(c.most_common(1)[0][1] for c in m.values())
        if tot: print(f'{A}->{B}: {cor}/{tot} = {cor/tot:.2f}')
EOF

