from collections import defaultdict,Counter
import itertools
d=defaultdict(dict)
for line in open('czn.trn'):
    l,w,f=line.rstrip('\n').split('\t')
    d[l][f.split(';')[1]]=w
asps=['PFV','HAB','POT','PROG']
def csuf(a,b):
    i=0
    while i<len(a) and i<len(b) and a[-1-i]==b[-1-i]: i+=1
    return i
pairs=defaultdict(list)
for l,forms in d.items():
    for S,T in itertools.permutations(asps,2):
        if S in forms and T in forms:
            fs,ft=forms[S],forms[T]
            k=csuf(fs,ft)
            pairs[(S,T)].append((l,fs[:len(fs)-k],ft[:len(ft)-k]))

srcw={'PFV':1.0,'HAB':1.0,'POT':0.95,'PROG':0.6}

def cand(S,T,fs,exclude):
    m=defaultdict(Counter)
    for (lm,preS,preT) in pairs[(S,T)]:
        if lm==exclude: continue
        m[preS][preT]+=1
    results=[]
    for preS,cnt in m.items():
        if fs.startswith(preS) and len(preS)<len(fs):
            preT,freq=cnt.most_common(1)[0]
            results.append((preT+fs[len(preS):],freq,len(preS)))
    return results

for scoremode in ['freq','freq-shortpref']:
    correct=0;tot=0
    for l,forms in d.items():
        for T,gold in forms.items():
            votes=Counter()
            for S in asps:
                if S==T or S not in forms: continue
                for pred,freq,plen in cand(S,T,forms[S],l):
                    if scoremode=='freq':
                        votes[pred]+=srcw[S]*freq
                    else:
                        votes[pred]+=srcw[S]*freq/(1+plen)
            tot+=1
            if votes and votes.most_common(1)[0][0]==gold: correct+=1
    print(scoremode,'acc:',correct/tot)
